const seedOSQuests = async () => {
    try {
        console.log("Connecting to Database... 🏛️");
        await mongoose.connect(process.env.MONGO_URI);

        await OSQuest.deleteMany({});

        const flattenedData = [];
        osCurriculum.forEach(floor => {
            floor.questions.forEach(q => {
                flattenedData.push({
                    subject: floor.subject,
                    floorId: floor.floorId,
                    floorName: floor.floorName,
                    floorBrief: floor.floorBrief,
                    ...q 
                });
            });
        });

        await OSQuest.insertMany(flattenedData);
        console.log(`✅ os_quests collection seeded with ${flattenedData.length} records!`);
        process.exit();
    } catch (err) {
        console.error("❌ Seed Error:", err);
        process.exit(1);
    }
};

seedOSQuests();